const config = $input.first().json;

// ── Rotação semanal automática ────────────────────────────────────────────
const WEEKLY_ROTATION = [
  'pornografia', // Dom
  'poder',       // Seg
  'traicao',     // Ter
  'pornografia', // Qua (repeat)
  'vicio',       // Qui
  'odio',        // Sex
  'ganancia'     // Sáb
];
const rawCat = (config.categoria || 'auto').toLowerCase().trim();
const categoria = rawCat === 'auto' || !rawCat
  ? WEEKLY_ROTATION[new Date().getDay()]
  : rawCat;

// ── Categorias: prompt de cena + hashtags base ────────────────────────────
const CATEGORIAS = {
  pornografia: {
    hookScenePrompt: 'Man alone late at night, face illuminated by phone screen with guilty expression of addiction and shame, dark room with cold blue digital light, slow motion close-up, cinematic vertical 9:16',
    hookTema: 'pornography addiction, digital darkness, shame and isolation',
    hashtagsBase: ['#libertacao', '#pureza', '#vidasanta', '#renovacao', '#vencendoovicio', '#liberdadeemcristo']
  },
  poder: {
    hookScenePrompt: 'Corporate executive stepping over others to climb the ladder, close-up on hands pushing faces down, cold hard light, corporate thriller aesthetic, cinematic vertical 9:16',
    hookTema: 'toxic ambition, power addiction, betrayal of values',
    hashtagsBase: ['#ambicao', '#lideranca', '#proposito', '#femdeus', '#humildade', '#carreira']
  },
  traicao: {
    hookScenePrompt: 'Two hands secretly touching under a restaurant table, wedding ring clearly visible on one finger, low angle camera, complicit dim restaurant lighting, cinematic vertical 9:16',
    hookTema: 'infidelity, marital betrayal, destructive secrets',
    hashtagsBase: ['#casamento', '#restauracao', '#perdao', '#familia', '#amor', '#cura']
  },
  vicio: {
    hookScenePrompt: 'Trembling hand opening a bottle at 7am, messy kitchen in background, harsh raw morning light, expression of desperate dependency, cinematic vertical 9:16',
    hookTema: 'alcohol and drug addiction, chemical dependency, family destruction',
    hashtagsBase: ['#libertacao', '#sobriedade', '#cura', '#renovacao', '#transformacao', '#milagre']
  },
  odio: {
    hookScenePrompt: 'Man typing a hateful message on phone in total darkness, expression of twisted pleasure, red lateral light, aggressive fingers on keyboard close-up, cinematic vertical 9:16',
    hookTema: 'hatred, desire for revenge, bitterness that destroys the hater',
    hashtagsBase: ['#perdao', '#paz', '#amor', '#cura', '#libertacao', '#gracadedeus']
  },
  ganancia: {
    hookScenePrompt: 'Hands counting money while blurred family waits at dinner table in background, face ignoring children, cold light on money and warm light on the ignored family, cinematic vertical 9:16',
    hookTema: 'greed, money above everything, family abandonment for wealth',
    hashtagsBase: ['#proposito', '#abencado', '#prosperidade', '#familia', '#eternidade', '#riqueza']
  }
};

const HASHTAGS_UNIVERSAL = [
  '#jesus', '#cristao', '#fe', '#evangelico', '#deus',
  '#reelscristao', '#shortscristao', '#vidacristao'
];

const cat = CATEGORIAS[categoria] || CATEGORIAS['pornografia'];

// ── Pool de CTAs: seguir/compartilhar centrado em Jesus ───────────────────
const CTA_POOL = [
  'Siga - Jesus tem mais pra voce',
  'Compartilhe: alguem precisa disso hoje',
  'Siga e nao perca a proxima revelacao',
  'Compartilhe - Jesus salva de verdade',
  'Siga: Deus ainda nao terminou com voce',
  'Compartilhe se cres no poder de Deus',
  'Siga - a proxima palavra e pra voce'
];
const ctaText = CTA_POOL[new Date().getDay() % CTA_POOL.length];

return [{
  json: {
    ...config,
    watermark: config.watermark || '@viver.em.jesus0',
    categoria,
    hookScenePrompt: cat.hookScenePrompt,
    hookTema: cat.hookTema,
    hashtagsBase: cat.hashtagsBase,
    hashtagsUniversal: HASHTAGS_UNIVERSAL,
    ctaText
  }
}];

// 1. Obtém o JSON de entrada do Gemini
const resp = $input.first().json;
let raw = "";

try {
  raw = resp.candidates[0].content.parts[0].text.trim();
} catch (e) {
  throw new Error('Resposta do Gemini malformada: ' + e.message);
}

// 2. Limpeza de Markdown
raw = raw.replace(/^```json\s*/i, '')
         .replace(/^```\s*/i, '')
         .replace(/```\s*$/i, '')
         .trim();

let concept = null;
try {
  const parsed = JSON.parse(raw);
  concept = Array.isArray(parsed) ? parsed[0] : parsed;
} catch (e) {
  throw new Error('JSON inválido vindo do Gemini: ' + raw.substring(0, 300));
}

// 3. Busca configurações upstream
let prev = {};
try { prev = $("Set Config PI").first().json; } catch (e) {
  prev = { GOOGLE_AI_API_KEY: '', ELEVENLABS_API_KEY: '' };
}

// 4. Hashtags: base por categoria + Gemini + universais (sem duplicatas)
let catData = {};
try { catData = $("Select Category").first().json; } catch(e) {}
const hashtagsBase      = catData.hashtagsBase      || [];
const hashtagsUniversal = catData.hashtagsUniversal || [];
const hashtagsGemini    = concept.hashtags          || [];
const hashtags = [...new Set([...hashtagsBase, ...hashtagsGemini, ...hashtagsUniversal])];

// 5. ID único
const videoId = 'PI_' + new Date().toISOString().replace(/[-T:.Z]/g, '').substring(0, 14);

return [{
  json: {
    videoId,
    tema_jesus:        concept.tema_jesus        || '',
    versiculo:         concept.versiculo         || '',
    hook_prompt_video: concept.hook_prompt_video || '',
    imagens_prompts:   concept.imagens_prompts   || [],
    narracao:          concept.narracao          || '',
    ctaText:           concept.ctaText           || catData.ctaText || 'Siga - Jesus tem mais pra voce',
    titulo:            concept.titulo            || '',
    titulo_yt:         concept.titulo_yt         || '',
    descricao:         concept.descricao         || '',
    hashtags,
    frase_hook:        concept.frase_hook        || '',
    frase_jesus:       concept.frase_jesus       || '',
    GOOGLE_AI_API_KEY: prev.GOOGLE_AI_API_KEY    || '',
    ELEVENLABS_API_KEY:prev.ELEVENLABS_API_KEY   || '',
    status: 'concept_ready'
  }
}];

const allItems = $input.all();

// Encontra os itens (com fallback seguro para não quebrar)
const hookData = allItems.find(i => i.json.hookReady) || { json: {} };
const imageData = allItems.find(i => i.json.imagesReady) || { json: {} };

// RESGATE DOS DADOS PERDIDOS:
// Como o Google Drive apagou os textos do JSON, vamos buscar lá do nó original
let originalData = {};
try {
  // Troque "Set Config PI" pelo nome exato do nó onde o Gemini montou os dados
  originalData = $('Parse Concept').first().json; 
} catch(e) {
  // Se não achar o nó, o workflow não trava
}

const videoId = imageData.json.videoId || hookData.json.videoId || originalData.videoId || 'PI_unknown';

return [{
  json: {
    videoId: videoId,
    titulo: imageData.json.titulo || originalData.titulo || '',
    descricao: imageData.json.descricao || originalData.descricao || '',
    hashtags: imageData.json.hashtags || originalData.hashtags || [],
    narracao: imageData.json.narracao || originalData.narracao || '',
    ctaText: imageData.json.ctaText || originalData.ctaText || '',
    watermark: imageData.json.watermark || originalData.watermark || '',
    hookVideoUrl: hookData.json.hookVideoUrl || '',
    images: imageData.json.images || [],
    GOOGLE_AI_API_KEY: imageData.json.GOOGLE_AI_API_KEY || originalData.GOOGLE_AI_API_KEY || '',
    frase_hook:  imageData.json.frase_hook  || originalData.frase_hook  || '',
    frase_jesus: imageData.json.frase_jesus || originalData.frase_jesus || ''
  }
}];

var childProcess = require('child_process');
var fs2 = require('fs');
var https2 = require('https');
var http2 = require('http');

var data = $input.first().json;
function execAsync(cmd, opts) {
  return new Promise(function(resolve, reject) {
    childProcess.exec(cmd, opts || {}, function(err, stdout, stderr) {
      if (err) { reject(new Error((stderr || '') + ' ' + err.message)); return; }
      resolve(stdout);
    });
  });
}
var videoId    = data.videoId;
var hookUrl    = data.hookVideoUrl;
var images     = (data.images || []).sort(function(a,b){ return (a.numero||0)-(b.numero||0); });
var ctaText    = data.ctaText   || '';
var titulo     = data.titulo    || '';
var fraseHook  = data.frase_hook  || '';
var fraseJesus = data.frase_jesus || '';
var watermark  = data.watermark   || '';

if (!hookUrl)       throw new Error('No hookVideoUrl');
if (!images.length) throw new Error('No images');

var MUSIC_TRACKS = [
  'https://cdn.pixabay.com/audio/2024/02/27/audio_6d33c54bfa.mp3',
  'https://cdn.pixabay.com/audio/2022/10/30/audio_0b4c6ed258.mp3'
];
var musicUrl = MUSIC_TRACKS[Math.floor(Math.random() * MUSIC_TRACKS.length)];
var SFX_URL = 'https://cdn.pixabay.com/audio/2022/03/24/audio_51d815d29b.mp3';

var tempDir = '/home/node/.n8n/temp/' + videoId;
fs2.mkdirSync(tempDir, { recursive: true });

function download(fileUrl, destPath) {
  return new Promise(function(resolve, reject) {
    var mod = fileUrl.startsWith('https:') ? https2 : http2;
    var file = fs2.createWriteStream(destPath);
    mod.get(fileUrl, { rejectUnauthorized: false }, function(res) {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        file.close(); fs2.unlinkSync(destPath);
        return download(res.headers.location, destPath).then(resolve).catch(reject);
      }
      res.pipe(file);
      file.on('finish', function() { file.close(resolve); });
      res.on('error', reject);
    }).on('error', function(err) { fs2.unlink(destPath, function(){}); reject(err); });
  });
}

// ── Fonts ─────────────────────────────────────────────────────────────────
var fontPath   = '/home/node/.n8n/temp/Roboto-Bold.ttf';
var cinzelPath = '/home/node/.n8n/temp/Cinzel-Bold.ttf';
if (!fs2.existsSync(fontPath)) {
  await download('https://github.com/google/fonts/raw/main/apache/roboto/static/Roboto-Bold.ttf', fontPath);
}
if (!fs2.existsSync(cinzelPath)) {
  await download('https://github.com/google/fonts/raw/main/ofl/cinzel/static/Cinzel-Bold.ttf', cinzelPath);
}

// ── Download assets ───────────────────────────────────────────────────────
var hookRaw   = tempDir + '/hook_raw.mp4';
var musicFile = tempDir + '/music.mp3';
var sfxFile   = tempDir + '/sfx.mp3';
await download(hookUrl,  hookRaw);
await download(musicUrl, musicFile);
var sfxOk = false;
try { await download(SFX_URL, sfxFile); sfxOk = true; } catch(e) { console.log('SFX skip:', e.message); }

var imgFiles = [];
for (var i = 0; i < images.length; i++) {
  var imgFile = tempDir + '/img_' + String(i+1).padStart(2,'0') + '.jpg';
  await download(images[i].url, imgFile);
  imgFiles.push(imgFile);
}

// ── Step 0: Hook — zoom in + color grade escuro/dessaturado ───────────────
var hookFile = tempDir + '/hook.mp4';
await execAsync(
  'ffmpeg -y -i "' + hookRaw + '"' +
  ' -vf "zoompan=z=\'1+0.25*(time/4)\':x=\'iw/2-(iw/zoom/2)\':y=\'ih/2-(ih/zoom/2)\':d=1:fps=25:s=1080x1920' +
  ',eq=saturation=0.6:brightness=-0.08,format=yuv420p"' +
  ' -c:v libx264 -preset veryfast -crf 23 "' + hookFile + '"',
  { timeout: 90000 }
);

// ── Step 1: Ken Burns — 3 variantes rotativas + warm grade ───────────────
// 0: zoom-in suave (devocional)
// 1: zoom-out dramático (revelação)
// 2: zoom-in celestial pelo topo (perspectiva divina)
var KB_VARIANTS = [
  { z: 'min(zoom+0.0010,1.3)', x: 'iw/2-(iw/zoom/2)', y: 'ih/2-(ih/zoom/2)' },
  { z: 'if(lte(zoom,1.0),1.5,max(1.0,zoom-0.0025))', x: 'iw/2-(iw/zoom/2)', y: 'ih/2-(ih/zoom/2)' },
  { z: 'min(zoom+0.0012,1.3)', x: 'iw/2-(iw/zoom/2)', y: '0' }
];

var kenBurnsClips = [];
for (var ki = 0; ki < imgFiles.length; ki++) {
  var kbFile = tempDir + '/kb_' + String(ki+1).padStart(2,'0') + '.mp4';
  var kbv = KB_VARIANTS[ki % 3];
  await execAsync(
    'ffmpeg -y -loop 1 -i "' + imgFiles[ki] + '"' +
    ' -vf "scale=2160:3840' +
    ',zoompan=z=\'' + kbv.z + '\':x=\'' + kbv.x + '\':y=\'' + kbv.y + '\':d=75:fps=25:s=1080x1920' +
    ',colorbalance=rs=0.15:gs=0.05:bs=-0.10:rm=0.10:gm=0.03:bm=-0.08' +
    ',format=yuv420p"' +
    ' -t 3 -c:v libx264 -preset veryfast -r 25 "' + kbFile + '"',
    { timeout: 120000 }
  );
  kenBurnsClips.push(kbFile);
}

// ── Step 2: Crossfade 0.7s ────────────────────────────────────────────────
var FADE = 0.7;
var CLIP_DUR = 3.0;
var editConcat, editDuration;
if (kenBurnsClips.length === 1) {
  editConcat = kenBurnsClips[0];
  editDuration = CLIP_DUR;
} else {
  var kbInputs = kenBurnsClips.map(function(f) { return '-i "' + f + '"'; }).join(' ');
  var filterParts = [];
  var prevLabel = '[0:v]';
  for (var fi = 1; fi < kenBurnsClips.length; fi++) {
    var offset = (fi * CLIP_DUR - fi * FADE).toFixed(2);
    var outLabel = fi === kenBurnsClips.length - 1 ? '[edit]' : '[xf' + fi + ']';
    filterParts.push(prevLabel + '[' + fi + ':v]xfade=transition=fade:duration=' + FADE + ':offset=' + offset + outLabel);
    prevLabel = outLabel;
  }
  editConcat = tempDir + '/edit.mp4';
  editDuration = kenBurnsClips.length * CLIP_DUR - (kenBurnsClips.length - 1) * FADE;
  await execAsync(
    'ffmpeg -y ' + kbInputs +
    ' -filter_complex "' + filterParts.join(';') + '"' +
    ' -map "[edit]" -c:v libx264 -preset veryfast -crf 23 -r 25 "' + editConcat + '"',
    { timeout: 300000 }
  );
}

// ── Step 3: Concat hook + edit ────────────────────────────────────────────
var concatList = tempDir + '/concat_pi.txt';
fs2.writeFileSync(concatList, "file '" + hookFile + "'\nfile '" + editConcat + "'");
var fullVideo = tempDir + '/full.mp4';
await execAsync(
  'ffmpeg -y -f concat -safe 0 -i "' + concatList + '"' +
  ' -c:v libx264 -preset veryfast -crf 23 -vf scale=1080:1920:flags=lanczos -an "' + fullVideo + '"',
  { timeout: 300000 }
);

// ── Step 4: Overlays + música + SFX + fade out ────────────────────────────
function escapeDrawtext(str) {
  return (str || '').replace(/\\/g,'').replace(/'/g,'\u2019').replace(/:/g,' -').replace(/[\[\]%]/g,'').replace(/\s{2,}/g,' ').trim();
}
function splitIntoLines(text, maxChars) {
  var t = escapeDrawtext(text || '');
  if (t.length <= maxChars) return [t, ''];
  var words = t.split(' ');
  var line1 = '';
  var line2 = '';
  for (var wi = 0; wi < words.length; wi++) {
    var candidate = line1 ? line1 + ' ' + words[wi] : words[wi];
    if (candidate.length <= maxChars) { line1 = candidate; }
    else { line2 = words.slice(wi).join(' '); break; }
  }
  return [line1, line2];
}

var hookLines  = splitIntoLines(fraseHook,  22);
var jesusLines = splitIntoLines(fraseJesus, 30);

var HOOK_DUR  = 3;
var CTA_DUR   = 4;
var ctaStart  = (HOOK_DUR + editDuration - CTA_DUR).toFixed(2);
var totalDur  = HOOK_DUR + editDuration;
var fadeOutSt = (totalDur - 1.2).toFixed(2);

var vfFilters = [];

// Vinheta nas bordas durante hook (0-3s)
vfFilters.push("drawbox=x=0:y=0:w=iw:h=ih*0.12:color=black@0.5:t=fill:enable='between(t,0,3)'");
vfFilters.push("drawbox=x=0:y=ih*0.88:w=iw:h=ih*0.12:color=black@0.5:t=fill:enable='between(t,0,3)'");
vfFilters.push("drawbox=x=0:y=0:w=iw*0.08:h=ih:color=black@0.3:t=fill:enable='between(t,0,3)'");
vfFilters.push("drawbox=x=iw*0.92:y=0:w=iw*0.08:h=ih:color=black@0.3:t=fill:enable='between(t,0,3)'");

// frase_hook — lower third (0-3s, Roboto, fade)
if (hookLines[0]) vfFilters.push(
  'drawtext=fontfile=' + fontPath +
  ':text=\'' + hookLines[0] + '\'' +
  ':fontsize=68:fontcolor=white:bordercolor=black@0.8:borderw=5' +
  ':x=(w-text_w)/2' +
  ':y=' + (hookLines[1] ? '(h*74)/100' : '(h*78)/100') +
  ':alpha=\'if(lt(t\\,0.5)\\,t/0.5\\,if(gt(t\\,2.5)\\,(3-t)/0.5\\,1))\'' +
  ':enable=\'between(t\\,0\\,3)\''
);
if (hookLines[1]) vfFilters.push(
  'drawtext=fontfile=' + fontPath +
  ':text=\'' + hookLines[1] + '\'' +
  ':fontsize=68:fontcolor=white:bordercolor=black@0.8:borderw=5' +
  ':x=(w-text_w)/2:y=(h*74)/100+80' +
  ':alpha=\'if(lt(t\\,0.5)\\,t/0.5\\,if(gt(t\\,2.5)\\,(3-t)/0.5\\,1))\'' +
  ':enable=\'between(t\\,0\\,3)\''
);

// Flash branco na transicao t=3
vfFilters.push("drawbox=x=0:y=0:w=iw:h=ih:color=white@0.85:t=fill:enable='between(t,3,3.1)'");
vfFilters.push("drawbox=x=0:y=0:w=iw:h=ih:color=white@0.55:t=fill:enable='between(t,3.1,3.2)'");
vfFilters.push("drawbox=x=0:y=0:w=iw:h=ih:color=white@0.25:t=fill:enable='between(t,3.2,3.3)'");

// frase_jesus — topo (3-7s, Cinzel, fade)
if (jesusLines[0]) vfFilters.push(
  'drawtext=fontfile=' + cinzelPath +
  ':text=\'' + jesusLines[0] + '\'' +
  ':fontsize=52:fontcolor=white:bordercolor=black@0.8:borderw=3' +
  ':x=(w-text_w)/2' +
  ':y=' + (jesusLines[1] ? '(h*10)/100' : '(h*11)/100') +
  ':alpha=\'if(lt(t\\,3.5)\\,(t-3)/0.5\\,if(gt(t\\,6.5)\\,(7-t)/0.5\\,1))\'' +
  ':enable=\'between(t\\,3\\,7)\''
);
if (jesusLines[1]) vfFilters.push(
  'drawtext=fontfile=' + cinzelPath +
  ':text=\'' + jesusLines[1] + '\'' +
  ':fontsize=52:fontcolor=white:bordercolor=black@0.8:borderw=3' +
  ':x=(w-text_w)/2:y=(h*10)/100+64' +
  ':alpha=\'if(lt(t\\,3.5)\\,(t-3)/0.5\\,if(gt(t\\,6.5)\\,(7-t)/0.5\\,1))\'' +
  ':enable=\'between(t\\,3\\,7)\''
);

// Watermark — canto inferior direito durante edit (após hook)
if (watermark) vfFilters.push(
  'drawtext=fontfile=' + fontPath +
  ':text=\'' + escapeDrawtext(watermark) + '\'' +
  ':fontsize=28:fontcolor=white@0.45:bordercolor=black@0.3:borderw=2' +
  ':x=(w-text_w)-30:y=(h-text_h)-60' +
  ':enable=\'gte(t\\,3)\''
);

// CTA amarelo — ultimos 4s
var ctaWords = (ctaText || 'Me siga para nao perder sua bencao').trim().split(/\s+/);
var mid = Math.ceil(ctaWords.length / 2);
var cta1 = escapeDrawtext(ctaWords.slice(0, mid).join(' '));
var cta2 = escapeDrawtext(ctaWords.slice(mid).join(' '));
var ctaEn = 'gte(t,' + ctaStart + ')';
if (cta1) vfFilters.push(
